import React from 'react';

export function Cards({ children }) {
    return <div className="grid">{children}</div>;
}

export function Card({ title, text, linkUrl, linkLabel = 'Open', hint }) {
    return (
        <div className="card">
            <div className="cardTitle">{title}</div>
            {text ? <div className="cardText">{text}</div> : null}
            {linkUrl ? (
                <a className="cardLink" href={linkUrl} target="_blank" rel="noreferrer">
                    {linkLabel}
                </a>
            ) : hint ? (
                <div className="cardHint">{hint}</div>
            ) : null}
        </div>
    );
}
